CREATE OR REPLACE FUNCTION fpb_kromss_get_share_coll ( as_reqno char ) RETURNS bigint AS $body$
DECLARE

ldc_share_coll  sc_lon_m_req_coll.req_amount%type;


BEGIN
  select  sum( sc_lon_m_req_coll.req_amount )
  into STRICT    ldc_share_coll
  from    sc_lon_m_req_coll
  where   sc_lon_m_req_coll.loan_requestment_no = as_reqno
  and     sc_lon_m_req_coll.collateral_type_code = '02';

  if coalesce(ldc_share_coll::text, '') = '' then ldc_share_coll := 0;end if;

  RETURN ldc_share_coll;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
